function formatDuration(ms: number): string {
  const hours = Math.floor(ms / 3600000)
  const minutes = Math.floor((ms % 3600000) / 60000)
  if (hours > 0) return `${hours}h ${minutes}m`
  return `${minutes}m`
}

AFTER:
const MS_PER_HOUR = 3_600_000
const MS_PER_MINUTE = 60_000

function formatDuration(ms: number): string {
  const hours = Math.floor(ms / MS_PER_HOUR)
  const minutes = Math.floor((ms % MS_PER_HOUR) / MS_PER_MINUTE)
  if (hours > 0) return `${hours}h ${minutes}m`
  return `${minutes}m`
}

const formattedDuration = computed(() => formatDuration(totalWorkDuration.value))

WHY: Eliminates duplicated math, fixes the inconsistency where total duration shows '0h 0m' instead of '0m', and centralizes the formatting logic in one place.
